function findTheLongestSubstring(s) {
    const pos = new Map();
    pos.set(0, -1);
    let ans = 0, n = s.length, i, cur = 0;
    for (i = 0; i < n; ++i) {
        switch (s.charAt(i)) {
            case 'a': cur ^= 1; break;
            case 'e': cur ^= 2; break;
            case 'i': cur ^= 4; break;
            case 'o': cur ^= 8; break;
            case 'u': cur ^= 16; break;
        }
        if(!pos.has(cur)) pos.set(cur, i);
        ans = Math.max(ans, i - pos.get(cur));
    }
    return ans;
}
```

