import java.util.HashMap;
import java.util.Map;

public int findTheLongestSubstring(String s) {
    Map<Integer, Integer> map = new HashMap<>();
    map.put(0, -1);
    int res = 0, n = s.length(), i, j = 0;
    for (i = 0; i < n; i++) {
        switch (s.charAt(i)) {
            case 'a': j ^= 1; break;
            case 'e': j ^= 2; break;
            case 'i': j ^= 4; break;
            case 'o': j ^= 8; break;
            case 'u': j ^= 16; break;
        }
        map.putIfAbsent(j, i);
        res = Math.max(res, i - map.get(j));
    }
    return res;
}
